          '\'use client\';\n\nimport { IconColorDark, IconColorLight } from \'@pierre/icons\';\nimport { useState } from \'react\';\n\nimport { AgentUi, type ThemeType } from \'./AgentUi\';\nimport { FeatureHeader } from \'@/components/FeatureHeader\';\nimport { ButtonGroup, ButtonGroupItem } from \'@/components/ui/button-group\';\n\ninterface AgentDemoSectionProps {\n  // Server-rendered, already-highlighted diff HTML keyed by file path. Built in\n  // Home.tsx so the embedded card paints highlighted on first load and hydrates\n  // without an SSR/client mismatch.\n  prerenderedDiffs: Record<string, string>;\n}\n\n// Homepage embed of the /aui agent review surface. It trims the standalone page\n// down to a single-file, diff-only card and lifts the light/dark control out\n// into an icon-only button group beside the section heading. It reuses the\n// homepage\'s shared worker pool, so it highlights with the pool\'s default\n// themes rather than the /aui page\'s soft themes.\nexport function AgentDemoSection({ prerenderedDiffs }: AgentDemoSectionProps) {\n  // The homepage demo always opens in dark mode regardless of the docs theme;\n  // visitors can flip it with the button group above the card.\n  const [themeType, setThemeType] = useState<ThemeType>(\'dark\');\n\n  return (\n    <div className="space-y-5">\n      <div className="flex flex-wrap items-start justify-between gap-4">\n        <FeatureHeader\n          id="edit"\n          isBeta\n          title="Edit diffs and code"\n          description={\n            <>\n              Enable edit mode in any <code>File</code> or <code>FileDiff</code>{\' \'}\n              component with the <code>EditProvider</code>. Includes support\n              for selection management, auto-indention, undo history,\n              find-in-file, lint markers, and more. Pairs nicely with{\' \'}\n              <code>@pierre/trees</code> for{\' \'}\n              <abbr title="Agentic User Interface">AUI</abbr> style experiences.\n            </>\n          }\n        />\n        <ButtonGroup\n          value={themeType}\n          onValueChange={(value) => setThemeType(value as ThemeType)}\n          aria-label="Theme"\n        >\n          <ButtonGroupItem value="light" aria-label="Light">\n            <IconColorLight className="size-4" />\n          </ButtonGroupItem>\n          <ButtonGroupItem value="dark" aria-label="Dark">\n            <IconColorDark className="size-4" />\n          </ButtonGroupItem>\n        </ButtonGroup>\n      </div>\n\n      <AgentUi themeType={themeType} prerenderedDiffs={prerenderedDiffs} />\n    </div>\n  );\n}\n',
